import { inView, animate } from "motion";

/**
 * Check if user prefers reduced motion
 */
export const prefersReducedMotion = (): boolean => {
  if (typeof window === "undefined") return false;
  return window.matchMedia("(prefers-reduced-motion: reduce)").matches;
};

/**
 * Animation directions for fade in
 */
export const fadeDirections = {
  up: { y: [30, 0] },
  down: { y: [-30, 0] },
  left: { x: [30, 0] },
  right: { x: [-30, 0] },
} as const;

export type FadeDirection = keyof typeof fadeDirections;

/**
 * Default animation config
 */
export const defaultAnimationConfig = {
  duration: 0.5,
  easing: [0.4, 0, 0.2, 1] as [number, number, number, number],
};

/**
 * Initialize fade-in animations for elements with .animate-on-scroll class
 */
export const initFadeInAnimations = (): void => {
  if (prefersReducedMotion()) return;

  inView(
    ".animate-on-scroll",
    (element) => {
      const direction = (element.getAttribute("data-direction") || "up") as FadeDirection;
      const delay = parseFloat(element.getAttribute("data-delay") || "0");

      animate(
        element,
        { 
          opacity: [0, 1], 
          ...fadeDirections[direction] 
        },
        { 
          duration: defaultAnimationConfig.duration, 
          easing: defaultAnimationConfig.easing,
          delay,
        }
      );
    },
    { amount: 0.2 }
  );
};

/**
 * Dynamic GSAP loader for CountUp component
 * Only loads GSAP when needed to minimize bundle size
 */
export const loadGSAP = async () => {
  const [gsapModule, scrollTriggerModule] = await Promise.all([
    import("gsap"),
    import("gsap/ScrollTrigger"),
  ]);

  const gsap = gsapModule.default;
  const { ScrollTrigger } = scrollTriggerModule;

  gsap.registerPlugin(ScrollTrigger);

  return { gsap, ScrollTrigger };
};

/**
 * Hero animation config
 */
export const heroAnimationConfig = {
  initial: { opacity: 0, y: 30 },
  animate: { opacity: 1, y: 0 },
  transition: { duration: 0.5, ease: [0.4, 0, 0.2, 1] },
};

/**
 * Card hover animation config
 */
export const cardHoverConfig = {
  scale: 1.02,
  transition: { duration: 0.2 },
};
```

