```tsx
import { useRef, useEffect, type ReactNode } from "react";
import { animate, stagger } from "motion";

interface HeroAnimationProps {
  children: ReactNode;
}

export default function HeroAnimation({ children }: HeroAnimationProps) {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    // Check for reduced motion preference
    const prefersReducedMotion = window.matchMedia(
      "(prefers-reduced-motion: reduce)"
    ).matches;

    if (prefersReducedMotion) {
      // Just show content immediately
      const elements = container.querySelectorAll(".hero-animate-item");
      elements.forEach((el) => {
        (el as HTMLElement).style.opacity = "1";
      });
      return;
    }

    // Get all direct children to animate
    const elements = container.children;

    // Set initial state
    Array.from(elements).forEach((el) => {
      (el as HTMLElement).style.opacity = "0";
      (el as HTMLElement).style.transform = "translateY(30px)";
    });

    // Animate each child with stagger
    animate(
      Array.from(elements),
      { opacity: [0, 1], y: [30, 0] },
      {
        duration: 0.6,
        easing: [0.4, 0, 0.2, 1],
        delay: stagger(0.15),
      }
    );
  }, []);

  return (
    <div ref={containerRef} className="hero-animation-container">
      {children}
    </div>
  );
}
```

