```tsx
import { useRef, useEffect, type ReactNode } from "react";
import { inView, animate } from "motion";

interface FadeInSectionProps {
  children: ReactNode;
  direction?: "up" | "down" | "left" | "right";
  delay?: number;
  threshold?: number;
  className?: string;
}

const directionMap = {
  up: { y: [30, 0] },
  down: { y: [-30, 0] },
  left: { x: [30, 0] },
  right: { x: [-30, 0] },
};

export default function FadeInSection({
  children,
  direction = "up",
  delay = 0,
  threshold = 0.2,
  className = "",
}: FadeInSectionProps) {
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const element = ref.current;
    if (!element) return;

    // Check for reduced motion preference
    const prefersReducedMotion = window.matchMedia(
      "(prefers-reduced-motion: reduce)"
    ).matches;

    if (prefersReducedMotion) {
      element.style.opacity = "1";
      return;
    }

    // Set initial state
    element.style.opacity = "0";

    const cleanup = inView(
      element,
      () => {
        animate(
          element,
          {
            opacity: [0, 1],
            ...directionMap[direction],
          },
          {
            duration: 0.5,
            easing: [0.4, 0, 0.2, 1],
            delay,
          }
        );
      },
      { amount: threshold }
    );

    return cleanup;
  }, [direction, delay, threshold]);

  return (
    <div ref={ref} className={className}>
      {children}
    </div>
  );
}
```

2. Create src/components/ui/CountUp.tsx:

```tsx
import { useRef, useEffect, useState } from "react";

interface CountUpProps {
  end: number;
  duration?: number;
  suffix?: string;
  prefix?: string;
  className?: string;
}

export default function CountUp({
  end,
  duration = 2000,
  suffix = "",
  prefix = "",
  className = "",
}: CountUpProps) {
  const ref = useRef<HTMLSpanElement>(null);
  const [hasAnimated, setHasAnimated] = useState(false);

  useEffect(() => {
    const element = ref.current;
    if (!element || hasAnimated) return;

    // Check for reduced motion preference
    const prefersReducedMotion = window.matchMedia(
      "(prefers-reduced-motion: reduce)"
    ).matches;

    if (prefersReducedMotion) {
      element.textContent = `${prefix}${end}${suffix}`;
      return;
    }

    // Use Intersection Observer to trigger animation when in view
    const observer = new IntersectionObserver(
      async (entries) => {
        const [entry] = entries;
        if (entry.isIntersecting && !hasAnimated) {
          setHasAnimated(true);
          observer.disconnect();

          // Dynamically load GSAP
          const { loadGSAP } = await import("../../lib/animations");
          const { gsap } = await loadGSAP();

          const counter = { value: 0 };
          gsap.to(counter, {
            value: end,
            duration: duration / 1000,
            ease: "power2.out",
            onUpdate: () => {
              if (element) {
                element.textContent = `${prefix}${Math.round(counter.value)}${suffix}`;
              }
            },
          });
        }
      },
      { threshold: 0.5 }
    );

    observer.observe(element);

    return () => observer.disconnect();
  }, [end, duration, suffix, prefix, hasAnimated]);

  return (
    <span ref={ref} className={className}>
      {prefix}0{suffix}
    </span>
  );
}
```

